from collections import deque
import sys
input = sys.stdin.readline

def solve():
    n, m = map(int, input().split())
    grid = []
    lab = None
    for i in range(n):
        row = input().strip()
        grid.append(list(row))
        for j in range(len(row)):
            if row[j] == 'L':
                lab = (i, j)

    dirs = [(-1,0),(1,0),(0,-1),(0,1)]
    bad = [[0]*m for _ in range(n)]
    good = [[False]*m for _ in range(n)]

    for i in range(n):
        for j in range(m):
            if grid[i][j] != '#':
                cnt = 0
                for di,dj in dirs:
                    ni,nj = i+di,j+dj
                    if 0<=ni<n and 0<=nj<m and grid[ni][nj]!='#':
                        cnt+=1
                bad[i][j] = cnt

    q = deque()
    li, lj = lab
    good[li][lj] = True
    q.append((li,lj))

    while q:
        x,y = q.popleft()
        for dx,dy in dirs:
            nx,ny = x+dx,y+dy
            if 0<=nx<n and 0<=ny<m and grid[nx][ny]!='#' and not good[nx][ny]:
                bad[nx][ny] -= 1
                if bad[nx][ny] <= 1:
                    good[nx][ny] = True
                    q.append((nx,ny))

    out = []
    for i in range(n):
        row = []
        for j in range(m):
            if grid[i][j]=='.':
                row.append('+' if good[i][j] else '.')
            else:
                row.append(grid[i][j])
        out.append(''.join(row))
    print('\n'.join(out))

t = int(input())
for _ in range(t):
    solve()

